import anthropic

client = anthropic.Anthropic()


def stream_response(prompt: str, system: str = "") -> None:
    """Print tokens as they arrive instead of waiting for the full response."""
    kwargs: dict = {
        "model": "claude-opus-4-5",
        "max_tokens": 1024,
        "messages": [{"role": "user", "content": prompt}],
    }
    if system:
        kwargs["system"] = system

    with client.messages.stream(**kwargs) as stream:
        for text in stream.text_stream:
            print(text, end="", flush=True)
    print()  # newline after streaming


stream_response(
    "Explain the difference between supervised and unsupervised learning in 3 paragraphs.",
    system="Be educational and precise.",
)

import anthropic
import json

client = anthropic.Anthropic()

tools = [
    {
        "name": "get_weather",
        "description": "Return the current weather for a city.",
        "input_schema": {
            "type": "object",
            "properties": {
                "city": {"type": "string", "description": "City name, e.g. 'Paris'"},
            },
            "required": ["city"],
        },
    }
]


def fake_get_weather(city: str) -> dict:
    """Stub — replace with a real API call."""
    return {"city": city, "temp_c": 18, "condition": "Partly cloudy"}


def chat_with_tools(user_message: str) -> str:
    messages = [{"role": "user", "content": user_message}]

    # First call — model may request a tool
    response = client.messages.create(
        model="claude-opus-4-5",
        max_tokens=512,
        tools=tools,
        messages=messages,
    )

    if response.stop_reason == "tool_use":
        # Execute the tool the model asked for
        tool_use_block = next(b for b in response.content if b.type == "tool_use")
        tool_result = fake_get_weather(**tool_use_block.input)

        # Feed result back to the model
        messages.append({"role": "assistant", "content": response.content})
        messages.append({
            "role": "user",
            "content": [{"type": "tool_result", "tool_use_id": tool_use_block.id,
                          "content": json.dumps(tool_result)}],
        })
        response = client.messages.create(
            model="claude-opus-4-5", max_tokens=512, tools=tools, messages=messages
        )

    return response.content[0].text


print(chat_with_tools("What is the weather like in Paris right now?"))
